import { useState } from 'react';
import { Link } from 'react-router-dom';
import AuraLogo from '@/components/AuraLogo';
import { getApiBase } from '@/utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './ForgotPasswordPage.module.css';

export default function ForgotPasswordPage() {
  usePageTitle('Forgot Password');
  const [step, setStep] = useState('email'); // email | code | success
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState('');

  const handleSendCode = async (e) => {
    e.preventDefault();
    setError('');
    setLoading('sending');
    try {
      const res = await fetch(`${getApiBase()}/auth/forgot-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.detail || 'Failed to send code');
        setLoading('');
        return;
      }
      setStep('code');
    } catch {
      setError('Connection failed. Is the API running?');
    }
    setLoading('');
  };

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setError('');

    if (newPassword.length < 8) {
      setError('Password must be at least 8 characters');
      return;
    }
    if (newPassword !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    setLoading('resetting');
    try {
      const res = await fetch(`${getApiBase()}/auth/reset-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, code, new_password: newPassword }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.detail || 'Failed to reset password');
        setLoading('');
        return;
      }
      setStep('success');
    } catch {
      setError('Connection failed. Is the API running?');
    }
    setLoading('');
  };

  const card = (title, subtitle, content) => (
    <div className={s.page}>
      <div className={s.card}>
        <div className={s.header}>
          <div className={s.logoWrap}>
            <AuraLogo variant="icon" height={52} glow />
          </div>
          <div className={s.title}>{title}</div>
          <div className={s.subtitle}>{subtitle}</div>
        </div>

        {error && (
          <div className={s.errorBox}>{typeof error === 'string' ? error : error?.message || 'An error occurred'}</div>
        )}

        {content}
      </div>
    </div>
  );

  // Step 1: Email
  if (step === 'email') {
    return card('Reset Password', 'Enter your email to receive a code', (
      <form onSubmit={handleSendCode}>
        <label className={s.label}>Email</label>
        <input
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          autoFocus
          autoComplete="email"
          placeholder="you@example.com"
          className={s.input}
        />
        <button type="submit" disabled={!!loading} className={s.submitBtn}>
          {loading === 'sending' ? 'Sending...' : 'Send Reset Code'}
        </button>
        <div className={s.backRow}>
          <Link to="/login" className={s.backLink}>Back to Sign In</Link>
        </div>
      </form>
    ));
  }

  // Step 2: Code + New Password
  if (step === 'code') {
    return card('Enter Code', `We sent a 6-digit code to ${email}`, (
      <form onSubmit={handleResetPassword}>
        <label className={s.label}>Verification Code</label>
        <input
          type="text"
          value={code}
          onChange={(e) => setCode(e.target.value)}
          required
          autoFocus
          maxLength={6}
          placeholder="123456"
          className={s.codeInput}
        />
        <label className={s.label}>New Password</label>
        <input
          type="password"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
          required
          autoComplete="new-password"
          placeholder="Min. 8 characters"
          className={s.input}
        />
        <label className={s.label}>Confirm Password</label>
        <input
          type="password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
          required
          autoComplete="new-password"
          placeholder="Repeat password"
          className={s.input}
        />
        <button type="submit" disabled={!!loading} className={s.submitBtn}>
          {loading === 'resetting' ? 'Resetting...' : 'Reset Password'}
        </button>
        <div className={s.backRow}>
          <Link to="/login" className={s.backLink}>Back to Sign In</Link>
        </div>
      </form>
    ));
  }

  // Step 3: Success
  return card('Password Reset', 'Your password has been updated', (
    <div className={s.successWrap}>
      <div className={s.successIcon}>&#10003;</div>
      <p className={s.successText}>
        You can now sign in with your new password.
      </p>
      <Link to="/login" className={s.successBtn}>Back to Sign In</Link>
    </div>
  ));
}
